-- Phase 5: agency portfolio, schedules, entitlements and commercial event ledger.
create table if not exists public.agencies (id uuid primary key default gen_random_uuid(),name text not null,slug text not null unique,status text not null default 'active' check(status in('trial','active','suspended','closed')),created_by uuid not null references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.agency_members (agency_id uuid not null references public.agencies(id) on delete cascade,user_id uuid not null references auth.users(id) on delete cascade,role text not null check(role in('agency_owner','agency_operator')),revoked_at timestamptz,created_at timestamptz not null default now(),primary key(agency_id,user_id));
create table if not exists public.agency_workspace_links (id uuid primary key default gen_random_uuid(),agency_id uuid not null references public.agencies(id) on delete cascade,workspace_id uuid not null references public.workspaces(id) on delete cascade,created_by uuid references auth.users(id),revoked_at timestamptz,created_at timestamptz not null default now(),unique(agency_id,workspace_id));
create table if not exists public.commercial_plans (key text primary key,name text not null,status text not null default 'active',brand_limit integer not null,monthly_observation_limit integer not null,monthly_run_limit integer not null,retention_days integer not null,features jsonb not null default '[]'::jsonb,configuration jsonb not null default '{}'::jsonb,created_at timestamptz not null default now());
insert into public.commercial_plans(key,name,brand_limit,monthly_observation_limit,monthly_run_limit,retention_days,features) values('manual-pilot','Manual pilot',5,5000,20,365,'["csv","agency_branding","scheduling"]'::jsonb) on conflict(key) do nothing;
create table if not exists public.workspace_subscriptions (id uuid primary key default gen_random_uuid(),workspace_id uuid not null unique references public.workspaces(id) on delete cascade,plan_key text not null references public.commercial_plans(key),status text not null check(status in('manual','trial','active','past_due','cancelled')),provider text,provider_customer_id text,provider_subscription_id text,current_period_start timestamptz,current_period_end timestamptz,last_event_at timestamptz,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.commercial_events (id uuid primary key default gen_random_uuid(),workspace_id uuid references public.workspaces(id) on delete cascade,provider text not null,provider_event_id text not null,event_type text not null,occurred_at timestamptz not null,payload jsonb not null default '{}'::jsonb,applied boolean not null default false,stale boolean not null default false,correlation_id text,created_at timestamptz not null default now(),unique(provider,provider_event_id));
create table if not exists public.usage_events (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,event_type text not null check(event_type in('brand_created','run_started','observation_accepted','report_published','share_opened','rerun_approved')),quantity integer not null default 1 check(quantity>=0),cost_micros bigint not null default 0,resource_id text,correlation_id text,occurred_at timestamptz not null default now(),metadata jsonb not null default '{}'::jsonb);
create table if not exists public.run_schedules (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,brand_id uuid not null references public.brands(id) on delete cascade,audit_configuration jsonb not null,cadence text not null check(cadence in('monthly','quarterly','one_time','incident')),timezone text not null default 'UTC',preferred_hour smallint check(preferred_hour between 0 and 23),status text not null default 'active' check(status in('active','paused','cancelled','completed')),next_run_at timestamptz,created_by uuid not null references auth.users(id),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.schedule_executions (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,schedule_id uuid not null references public.run_schedules(id) on delete cascade,execution_key text not null unique,scheduled_for timestamptz not null,audit_run_id uuid references public.audit_runs(id),state text not null check(state in('claimed','started','completed','failed','skipped')),reason text,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table if not exists public.notification_deliveries (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,event_type text not null,channel text not null check(channel in('email','webhook','in_app')),destination_hash text,idempotency_key text not null unique,state text not null check(state in('planned','sent','failed','suppressed')),payload jsonb not null default '{}'::jsonb,attempted_at timestamptz,created_at timestamptz not null default now());
create table if not exists public.agency_branding (agency_id uuid primary key references public.agencies(id) on delete cascade,logo_url text,accent text,report_footer text,updated_by uuid references auth.users(id),updated_at timestamptz not null default now());
create table if not exists public.report_templates (id uuid primary key default gen_random_uuid(),agency_id uuid references public.agencies(id) on delete cascade,name text not null,configuration jsonb not null,active boolean not null default true,created_by uuid references auth.users(id),created_at timestamptz not null default now());
create table if not exists public.rerun_approvals (id uuid primary key default gen_random_uuid(),workspace_id uuid not null references public.workspaces(id) on delete cascade,report_version_id uuid not null references public.report_versions(id) on delete restrict,requested_by uuid not null references auth.users(id),decision text not null check(decision in('approved','declined','pending')),notes text,created_at timestamptz not null default now(),unique(report_version_id,requested_by));
create or replace function public.is_agency_member(target_agency_id uuid) returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.agency_members where agency_id=target_agency_id and user_id=auth.uid() and revoked_at is null) $$;
create or replace function public.agency_can_access_workspace(target_workspace_id uuid) returns boolean language sql stable security definer set search_path=public as $$ select exists(select 1 from public.agency_workspace_links l join public.agency_members m on m.agency_id=l.agency_id where l.workspace_id=target_workspace_id and l.revoked_at is null and m.user_id=auth.uid() and m.revoked_at is null) $$;
revoke all on function public.is_agency_member(uuid) from public;grant execute on function public.is_agency_member(uuid) to authenticated,service_role;revoke all on function public.agency_can_access_workspace(uuid) from public;grant execute on function public.agency_can_access_workspace(uuid) to authenticated,service_role;
alter table public.agencies enable row level security;alter table public.agency_members enable row level security;alter table public.agency_workspace_links enable row level security;alter table public.workspace_subscriptions enable row level security;alter table public.commercial_events enable row level security;alter table public.usage_events enable row level security;alter table public.run_schedules enable row level security;alter table public.schedule_executions enable row level security;alter table public.notification_deliveries enable row level security;alter table public.agency_branding enable row level security;alter table public.report_templates enable row level security;alter table public.rerun_approvals enable row level security;
create policy agencies_read on public.agencies for select using(public.is_agency_member(id));create policy agency_members_read on public.agency_members for select using(public.is_agency_member(agency_id));create policy agency_links_read on public.agency_workspace_links for select using(public.is_agency_member(agency_id));
create policy subscriptions_read on public.workspace_subscriptions for select using(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));create policy usage_read on public.usage_events for select using(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));
create policy schedules_read on public.run_schedules for select using(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));create policy schedules_manage on public.run_schedules for all using(public.has_workspace_role(workspace_id,array['owner','operator']) or public.agency_can_access_workspace(workspace_id)) with check(public.has_workspace_role(workspace_id,array['owner','operator']) or public.agency_can_access_workspace(workspace_id));
create policy executions_read on public.schedule_executions for select using(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));create policy notifications_read on public.notification_deliveries for select using(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));
create policy rerun_read on public.rerun_approvals for select using(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));create policy rerun_write on public.rerun_approvals for insert with check(public.is_workspace_member(workspace_id) or public.agency_can_access_workspace(workspace_id));
create or replace function public.prevent_commercial_event_mutation() returns trigger language plpgsql as $$ begin raise exception 'commercial and usage events are append-only'; end; $$;
create trigger commercial_events_immutable before update or delete on public.commercial_events for each row when(old.applied=true) execute function public.prevent_commercial_event_mutation();create trigger usage_events_immutable before update or delete on public.usage_events for each row execute function public.prevent_commercial_event_mutation();
